// TmUniverse yields t and all transitive Tm subterms, preorder.
func TmUniverse(t Tm) iter.Seq[Tm] {
	return func(yield func(Tm) bool) {
		var walk func(Tm) bool
		walk = func(cur Tm) bool {
			if !yield(cur) {
				return false
			}
			for _, c := range TmChildren(cur) {
				if !walk(c) {
					return false
				}
			}
			return true
		}
		walk(t)
	}
}

// TmTransform rewrites t bottom-up: children first, then f at each node.
